+
+// ─── Ambient Sound Indicators ───────────────────────────────────────
+
+interface SoundIndicator {
+  x: number;
+  y: number;
+  type: 'music' | 'hammer' | 'quill';
+  frame: number;
+}
+
+const soundIndicators: SoundIndicator[] = [];
+
+/**
+ * Draws animated ambient sound indicators near specific furniture areas.
+ * Types:
+ * - 'music': musical notes near bard area
+ * - 'hammer': hammer impact lines near forge
+ * - 'quill': small motion lines near scriptorium
+ */
+export function drawSoundIndicator(
+  ctx: CanvasRenderingContext2D,
+  roomType: string,
+  x: number,
+  y: number,
+  w: number,
+  h: number,
+  frame: number,
+) {
+  // Clear old indicators occasionally
+  if (frame % 120 === 0) {
+    soundIndicators.length = 0;
+  }
+
+  // Spawn new indicators randomly per room type
+  if (frame % 30 === 0) {
+    switch (roomType) {
+      case 'scribe':
+        // Quill scratching near scriptorium desk
+        soundIndicators.push({
+          x: x + w * 0.6 + (Math.random() - 0.5) * 10,
+          y: y + h * 0.6 + (Math.random() - 0.5) * 6,
+          type: 'quill',
+          frame: 0,
+        });
+        break;
+      case 'blacksmith':
+        // Hammer impacts near forge
+        soundIndicators.push({
+          x: x + w * 0.5 + (Math.random() - 0.5) * 12,
+          y: y + h * 0.5 + (Math.random() - 0.5) * 8,
+          type: 'hammer',
+          frame: 0,
+        });
+        break;
+      case 'nobility':
+      case 'king':
+        // Musical notes near bard area (assumed nobility/king rooms)
+        soundIndicators.push({
+          x: x + w * 0.4 + (Math.random() - 0.5) * 10,
+          y: y + h * 0.5 + (Math.random() - 0.5) * 8,
+          type: 'music',
+          frame: 0,
+        });
+        break;
+    }
+  }
+
+  // Draw and animate indicators
+  for (let i = soundIndicators.length - 1; i >= 0; i--) {
+    const ind = soundIndicators[i];
+    ind.frame++;
+    const alpha = 1 - ind.frame / 60;
+    if (alpha <= 0) {
+      soundIndicators.splice(i, 1);
+      continue;
+    }
+    ctx.save();
+    ctx.globalAlpha = alpha;
+    ctx.lineCap = 'round';
+    ctx.lineJoin = 'round';
+    ctx.lineWidth = 2;
+    ctx.translate(ind.x, ind.y);
+    switch (ind.type) {
+      case 'music':
+        // Draw simple musical note shape, oscillate up/down
+        ctx.strokeStyle = '#ffd700';
+        ctx.fillStyle = '#ffd700';
+        const noteY = Math.sin(ind.frame * 0.3) * 3;
+        ctx.beginPath();
+        ctx.moveTo(0, noteY);
+        ctx.lineTo(0, noteY - 10);
+        ctx.quadraticCurveTo(4, noteY - 12, 6, noteY - 6);
+        ctx.quadraticCurveTo(4, noteY - 4, 0, noteY);
+        ctx.fill();
+        ctx.beginPath();
+        ctx.arc(6, noteY - 6, 3, 0, Math.PI * 2);
+        ctx.fill();
+        break;
+      case 'hammer':
+        // Draw impact lines radiating outward, fade and shrink
+        ctx.strokeStyle = '#f08030';
+        const len = 8 * (1 - ind.frame / 60);
+        ctx.beginPath();
+        ctx.moveTo(0, 0);
+        ctx.lineTo(len, 0);
+        ctx.moveTo(0, 0);
+        ctx.lineTo(-len, 0);
+        ctx.moveTo(0, 0);
+        ctx.lineTo(0, len);
+        ctx.moveTo(0, 0);
+        ctx.lineTo(0, -len);
+        ctx.stroke();
+        break;
+      case 'quill':
+        // Draw small motion lines, flickering
+        ctx.strokeStyle = '#8a7a5a';
+        const flicker = (ind.frame % 20) < 10 ? 1 : 0.5;
+        ctx.lineWidth = 1.5 * flicker;
+        ctx.beginPath();
+        ctx.moveTo(0, 0);
+        ctx.lineTo(4, -3);
+        ctx.moveTo(1, 1);
+        ctx.lineTo(5, -2);
+        ctx.stroke();
+        break;
+    }
+    ctx.restore();
+  }
+}
+
